func solve(n int64, edges [][]int64, label string) int64 {
	// Build adjacency list
	adj := make([][]int64, n)
	for _, edge := range edges {
		u, v := edge[0], edge[1]
		adj[u] = append(adj[u], v)
		adj[v] = append(adj[v], u)
	}

	// Memoization cache for visited nodes
	memo := make(map[string]int64)

	// DFS function to find the longest palindrome
	var dfs func(int64, int64, int64, int64) int64
	dfs = func(node int64, prev int64, visited int64, currentLen int64) int64 {
		// Check if we have already computed this state
		state := fmt.Sprintf("%d-%d-%d", node, prev, visited)
		if val, ok := memo[state]; ok {
			return val
		}

		// If we have visited all nodes, return the current length
		if visited == (1 << n) - 1 {
			return currentLen
		}

		maxLen := 0

		// Try to move to each neighbor
		for _, neighbor := range adj[node] {
			// Skip if the neighbor is already visited
			if (visited & (1 << neighbor)) != 0 {
				continue
			}

			// Check if the current path can form a palindrome
			// If the current node is the same as the previous node, it's a palindrome of length 1
			// Otherwise, check if the current node's label is the same as the previous node's label
			if node == prev {
				newLen := currentLen + 1
				if newLen > maxLen {
					maxLen = newLen
				}
			} else if label[int(node)] == label[int(prev)] {
				newLen := currentLen + 2
				if newLen > maxLen {
					maxLen = newLen
				}
			}

			// Recursively explore the next node
			newVisited := visited | (1 << neighbor)
			newLen := dfs(neighbor, node, newVisited, currentLen+1)
			if newLen > maxLen {
				maxLen = newLen
			}
		}

		// Memoize the result for this state
		memo[state] = int64(maxLen)
		return int64(maxLen)
	}

	// Try all starting nodes
	maxPalindromeLength := 0
	for i := 0; i < int(n); i++ {
		visited := 1 << int64(i)
		result := dfs(int64(i), -1, visited, 1)
		if result > maxPalindromeLength {
			maxPalindromeLength = result
		}
	}

	return int64(maxPalindromeLength)
}
